/// <summary>
/// Purchase agreement line import
/// </summary>
public class ETG_Acu_PurchAgreementLineImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_PurchAgreementLineImport  purchAgreementLineimport;

    purchAgreementLineimport = ETG_Acu_PurchAgreementLineImport::construct();

    if (purchAgreementLineimport.prompt())
    {
        purchAgreementLineimport.runOperation();
    }
}

public static ETG_Acu_PurchAgreementLineImport construct()
{
    return new ETG_Acu_PurchAgreementLineImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    PurchPurchaseAgreementLineV2Entity      purchAgreementLine;
    PurchPurchaseAgreementHeaderV2Entity    purchAgreementHeader;

    purchAgreementLine.PURCHASEAGREEMENTID                  = conpeek(_con, 1);

    select firstonly purchAgreementHeader
        where purchAgreementHeader.PurchAgreementId == purchAgreementLine.PURCHASEAGREEMENTID;

    purchAgreementLine.LineNumber                           = conpeek(_con, 2);
    purchAgreementLine.CommitmentType                       = purchAgreementHeader.DefaultCommitmentType;
    purchAgreementLine.CommittedQuantity                    = conpeek(_con, 4);
    //purchAgreementLine.DefaultLedgerDimensionDisplayValue   = conpeek(_con, 5);
    purchAgreementLine.EffectiveDate                        = purchAgreementHeader.DefaultEffectiveDate;
    purchAgreementLine.ETG_OverDeliveryPct                  = conpeek(_con, 7);
    purchAgreementLine.ETG_PriceType                        = conpeek(_con, 8);
    purchAgreementLine.ETG_UnderDeliveryPct                 = conpeek(_con, 9);
    purchAgreementLine.ExpirationDate                       = purchAgreementHeader.DefaultExpirationDate;
    purchAgreementLine.InvoiceVendorAccountNumber           = purchAgreementHeader.InvoiceVendorAccountNumber;
    purchAgreementLine.ItemNumber                           = conpeek(_con, 12);
    purchAgreementLine.Price                                = conpeek(_con, 13);
    purchAgreementLine.ProductColorId                       = conpeek(_con, 14);
    purchAgreementLine.ProductConfigurationId               = conpeek(_con, 15);
    purchAgreementLine.ProductSizeId                        = conpeek(_con, 16);
    purchAgreementLine.ProductStyleId                       = conpeek(_con, 17);
    purchAgreementLine.PurchaseAgreementLegalEntityId       = curExt();
    purchAgreementLine.ReceivingSiteId                      = conpeek(_con, 19);
    purchAgreementLine.ReceivingWarehouseId                 = conpeek(_con, 20);
    purchAgreementLine.UnitSymbol                           = conpeek(_con, 21);

    // BusinessUnit (23)	Contract (24)	Department (25)	Intercompany (26)	Plant_Warehouse_Office (27)	Product_Service (28)	Trader_Employee (29)
    // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

    purchAgreementLine.DefaultLedgerDimensionDisplayValue  = conPeek(_con, 26) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 24) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 28) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 27) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 22) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 25) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 23);
    if (purchAgreementLine.validateWrite())
    {
        purchAgreementLine.insert();
    }
    else
    {
        throw error("Error while inserting purch agreement line");
    }
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = 'Import purchase agreement line';

    return ret;
}
